BEGIN TRANSACTION;
CREATE TABLE "accounts_auditlog" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "action" varchar(20) NOT NULL, "object_id" integer unsigned NULL CHECK ("object_id" >= 0), "object_repr" varchar(200) NOT NULL, "detail" text NOT NULL, "ip_address" char(39) NULL, "user_agent" varchar(300) NOT NULL, "created_at" datetime NOT NULL, "user_id" bigint NULL REFERENCES "accounts_user" ("id") DEFERRABLE INITIALLY DEFERRED, "changes" text NULL CHECK ((JSON_VALID("changes") OR "changes" IS NULL)), "level" varchar(10) NOT NULL, "object_url" varchar(300) NOT NULL, "module" varchar(20) NOT NULL);
CREATE TABLE "accounts_user" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "password" varchar(128) NOT NULL, "last_login" datetime NULL, "is_superuser" bool NOT NULL, "username" varchar(150) NOT NULL UNIQUE, "first_name" varchar(150) NOT NULL, "last_name" varchar(150) NOT NULL, "email" varchar(254) NOT NULL, "is_staff" bool NOT NULL, "is_active" bool NOT NULL, "date_joined" datetime NOT NULL, "role" varchar(20) NOT NULL, "telephone" varchar(30) NOT NULL, "avatar" varchar(100) NULL, "client_profile_id" bigint NULL UNIQUE REFERENCES "campaigns_client" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "accounts_user_groups" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" bigint NOT NULL REFERENCES "accounts_user" ("id") DEFERRABLE INITIALLY DEFERRED, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "accounts_user_user_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" bigint NOT NULL REFERENCES "accounts_user" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "auth_group" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(150) NOT NULL UNIQUE);
CREATE TABLE "auth_group_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "auth_permission" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "content_type_id" integer NOT NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "codename" varchar(100) NOT NULL, "name" varchar(255) NOT NULL);
CREATE TABLE "campaigns_campagne" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nom" varchar(200) NOT NULL, "reference" varchar(50) NOT NULL UNIQUE, "date_debut" date NOT NULL, "date_fin" date NOT NULL, "statut" varchar(20) NOT NULL, "type_support" varchar(10) NOT NULL, "duree_passage" integer unsigned NULL CHECK ("duree_passage" >= 0), "tranches_horaires" varchar(500) NOT NULL, "notes" text NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "created_by_id" bigint NULL REFERENCES "accounts_user" ("id") DEFERRABLE INITIALLY DEFERRED, "client_id" bigint NOT NULL REFERENCES "campaigns_client" ("id") DEFERRABLE INITIALLY DEFERRED, "contrat_id" bigint NULL REFERENCES "campaigns_contrat" ("id") DEFERRABLE INITIALLY DEFERRED, "frequence" integer unsigned NULL CHECK ("frequence" >= 0));
CREATE TABLE "campaigns_campagnevisuel" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "fichier" varchar(100) NOT NULL, "campagne_id" bigint NOT NULL REFERENCES "campaigns_campagne" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "campaigns_client" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nom" varchar(200) NOT NULL, "contact_nom" varchar(150) NOT NULL, "telephone" varchar(30) NOT NULL, "email" varchar(254) NOT NULL, "adresse" text NOT NULL, "logo" varchar(100) NULL, "notes" text NOT NULL, "created_at" datetime NOT NULL, "actif" bool NOT NULL);
CREATE TABLE "campaigns_contrat" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "type_contrat" varchar(20) NOT NULL, "date_debut" date NOT NULL, "date_fin" date NOT NULL, "nb_spots" integer unsigned NOT NULL CHECK ("nb_spots" >= 0), "actif" bool NOT NULL, "notes" text NOT NULL, "created_at" datetime NOT NULL, "client_id" bigint NOT NULL REFERENCES "campaigns_client" ("id") DEFERRABLE INITIALLY DEFERRED, "nom" varchar(200) NOT NULL);
CREATE TABLE "campaigns_lignecampagne" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "visuel" varchar(100) NULL, "ordre_dans_boucle" integer unsigned NOT NULL CHECK ("ordre_dans_boucle" >= 0), "notes" text NOT NULL, "campagne_id" bigint NOT NULL REFERENCES "campaigns_campagne" ("id") DEFERRABLE INITIALLY DEFERRED, "face_id" bigint NULL REFERENCES "inventory_facepanneau" ("id") DEFERRABLE INITIALLY DEFERRED, "support_id" bigint NOT NULL REFERENCES "inventory_support" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "django_admin_log" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "object_id" text NULL, "object_repr" varchar(200) NOT NULL, "action_flag" smallint unsigned NOT NULL CHECK ("action_flag" >= 0), "change_message" text NOT NULL, "content_type_id" integer NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" bigint NOT NULL REFERENCES "accounts_user" ("id") DEFERRABLE INITIALLY DEFERRED, "action_time" datetime NOT NULL);
CREATE TABLE "django_content_type" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app_label" varchar(100) NOT NULL, "model" varchar(100) NOT NULL);
CREATE TABLE "django_migrations" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app" varchar(255) NOT NULL, "name" varchar(255) NOT NULL, "applied" datetime NOT NULL);
CREATE TABLE "django_session" ("session_key" varchar(40) NOT NULL PRIMARY KEY, "session_data" text NOT NULL, "expire_date" datetime NOT NULL);
CREATE TABLE "inventory_ecrannumerique" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "type_ecran" varchar(20) NOT NULL, "resolution" varchar(10) NOT NULL, "heure_allumage" time NOT NULL, "heure_extinction" time NOT NULL, "support_id" bigint NOT NULL UNIQUE REFERENCES "inventory_support" ("id") DEFERRABLE INITIALLY DEFERRED, "cellule" varchar(10) NOT NULL);
CREATE TABLE "inventory_facepanneau" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "label" varchar(1) NOT NULL, "eclairage" varchar(10) NOT NULL, "notes" text NOT NULL, "support_id" bigint NOT NULL REFERENCES "inventory_support" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "inventory_photomaintenance" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "photo" varchar(100) NOT NULL, "legende" varchar(200) NOT NULL, "uploaded_at" datetime NOT NULL, "etat_apres" varchar(20) NOT NULL, "uploaded_by_id" bigint NULL REFERENCES "accounts_user" ("id") DEFERRABLE INITIALLY DEFERRED, "support_id" bigint NOT NULL REFERENCES "inventory_support" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "inventory_support" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "code" varchar(30) NOT NULL UNIQUE, "nom" varchar(200) NOT NULL, "type_support" varchar(10) NOT NULL, "latitude" decimal NOT NULL, "longitude" decimal NOT NULL, "adresse" varchar(300) NOT NULL, "ville" varchar(100) NOT NULL, "quartier" varchar(100) NOT NULL, "etat" varchar(20) NOT NULL, "date_installation" date NOT NULL, "notes" text NOT NULL, "photo_principale" varchar(100) NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "created_by_id" bigint NULL REFERENCES "accounts_user" ("id") DEFERRABLE INITIALLY DEFERRED, "format" varchar(20) NOT NULL);
CREATE TABLE "planning_logdiffusion" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "timestamp" datetime NOT NULL, "duree_sec" integer unsigned NOT NULL CHECK ("duree_sec" >= 0), "genere_auto" bool NOT NULL, "campagne_id" bigint NULL REFERENCES "campaigns_campagne" ("id") DEFERRABLE INITIALLY DEFERRED, "client_id" bigint NULL REFERENCES "campaigns_client" ("id") DEFERRABLE INITIALLY DEFERRED, "ecran_id" bigint NOT NULL REFERENCES "inventory_ecrannumerique" ("id") DEFERRABLE INITIALLY DEFERRED, "ligne_id" bigint NULL REFERENCES "campaigns_lignecampagne" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE INDEX "inventory_photomaintenance_uploaded_by_id_8bb159a7" ON "inventory_photomaintenance" ("uploaded_by_id");
